import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner scanner = new Scanner(System.in);

        // Solution as follows
        int t = scanner.nextInt();
        scanner.nextLine(); // Consume the newline
        for (int j = 0; j < t; j++) {
            String A = scanner.nextLine();
            String B = scanner.nextLine();

            int i = 0;
            int n = A.length();
            // Flag is a very important tool in programming problems - you will come across various examples in later problems as well
            boolean flag = false;

            while (i < n) {
                // Checking A from left to right and B from right to left
                if (A.charAt(i) == B.charAt(n - i - 1)) {
                    i = i + 1;
                } else {
                    // If specific character in A and B do not match, then they cannot be reverse
                    flag = true;
                    break;
                }
            }

            if (flag) {
                System.out.println("NO");
            } else {
                System.out.println("YES");
            }
        }

        scanner.close();
    }
}
